@EndUserText.label: 'Complex Stock Calculation via AMDP'
@ObjectModel.resultSetType: #CALCULATION_ENGINE
define table function Z_Stock_Projection
  with parameters
    @Environment.systemField: #SYSTEM_DATE
    P_KeyDate  : dats,
    P_Material : matnr
  returns
{
  key Material     : matnr;
  key Plant        : werks_d;
      StockQty     : menge_d;
      StockValue   : wrbtr;
      ProjectedATP : menge_d;
}

" AMDP implementation: multi-step calculation
METHOD stock_projection
  BY DATABASE FUNCTION FOR HDB
  LANGUAGE SQLSCRIPT
  USING I_MaterialStock I_MaterialDocument I_Reservation.
  lt_current = select Material, Plant, StockQty, StockValue
    from I_MaterialStock where Material = :P_Material;
  lt_incoming = select Material, Plant,
    sum(Quantity) as IncomingQty
    from I_MaterialDocument
    where Material = :P_Material
      and PostingDate > :P_KeyDate
      and MovementType in ('101','561')
    group by Material, Plant;
  et_result = select ... from :lt_current ... join :lt_incoming ... ;
ENDMETHOD.
